const tz = 'Asia/Kolkata';
const now = new Date();
const today = new Intl.DateTimeFormat('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' }).format(now);
const label = new Intl.DateTimeFormat('en-US', { timeZone: tz, year: 'numeric', month: 'short', day: 'numeric' }).format(now);

const userPrompt = [
  `Today is ${today}. Use web search to find today's most important real news from the last 24 hours, then produce PULSE's daily briefing.`,
  ``,
  `Return ONE JSON object with EXACTLY this shape:`,
  `{`,
  `  "date": "${today}",`,
  `  "updated": "${today}",`,
  `  "brand": "PULSE",`,
  `  "stories": [`,
  `    {"cat": "World", "lead": true, "title": "...", "summary": "...", "source": "...", "url": "..."}`,
  `  ]`,
  `}`,
  ``,
  `Rules:`,
  `- Cover these categories, about 3 stories each: World, Business, Tech & AI, Crypto, Science, Health, Sports, Culture. Aim for about 24 stories total.`,
  `- EXACTLY ONE story has "lead": true (the single biggest story of the day). Every other story omits the lead field.`,
  `- title: a concise headline under 90 characters. summary: 1-2 factual sentences. source: the outlet name. url: a real, working link to the original article you found via web search (the article page, not a homepage).`,
  `- Only include real, verifiable stories from reputable outlets found via web search. Never invent stories or URLs.`,
  `- Output ONLY the JSON object: no markdown, no code fences, no commentary before or after.`
].join('\n');

return [{ json: {
  today,
  label,
  requestBody: {
    model: 'claude-sonnet-4-6',
    max_tokens: 8000,
    system: 'You are the news editor for PULSE, a daily world briefing. You search the web for the most important real news of the day and output a single strict JSON object with no extra text.',
    tools: [{ type: 'web_search_20250305', name: 'web_search', max_uses: 8 }],
    messages: [{ role: 'user', content: userPrompt }]
  }
} }];

const resp = $input.first().json;

// 1) Collect all text blocks from Claude's response
let text = '';
if (Array.isArray(resp.content)) {
  text = resp.content.filter(b => b && b.type === 'text').map(b => b.text).join('\n');
}
if (!text || !text.trim()) {
  throw new Error('No text returned from Claude. Check the API key, model name, or web search tool.');
}

// 2) Extract the JSON object (tolerate code fences / stray prose)
let raw = text.trim();
const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
if (fence) raw = fence[1].trim();
const start = raw.indexOf('{');
const end = raw.lastIndexOf('}');
if (start === -1 || end === -1) {
  throw new Error('No JSON object found in Claude output.');
}
const jsonStr = raw.slice(start, end + 1);

let data;
try {
  data = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Claude output was not valid JSON: ' + e.message);
}

// 3) Validate (mirrors the publish-safety checks)
if (!data.stories || !Array.isArray(data.stories) || data.stories.length === 0) {
  throw new Error('Validation failed: stories array is empty or missing.');
}
const leads = data.stories.filter(s => s && s.lead === true);
if (leads.length !== 1) {
  throw new Error('Validation failed: need exactly ONE lead story, found ' + leads.length + '.');
}
for (const s of data.stories) {
  if (!s.cat || !s.title || !s.summary || !s.source || !s.url) {
    throw new Error('Validation failed: a story is missing a required field (cat/title/summary/source/url).');
  }
}

// 4) Normalise metadata
const today = $('Prep').first().json.today;
const label = $('Prep').first().json.label;
data.date = today;
data.updated = today;
data.brand = 'PULSE';

const pretty = JSON.stringify(data, null, 2);
const contentB64 = Buffer.from(pretty, 'utf8').toString('base64');

return [{ json: {
  storyCount: data.stories.length,
  today,
  label,
  storiesJson: pretty,
  storiesB64: contentB64
} }];

const gh = $input.first().json;
let status = {};
try {
  const decoded = Buffer.from((gh.content || '').replace(/\s/g, ''), 'base64').toString('utf8');
  status = JSON.parse(decoded);
} catch (e) {
  status = {};
}

const p = $('Parse & validate').first().json;
const nowISO = new Date().toISOString();

status.lastNewsRunISO = nowISO;
status.lastNewsRunLabel = p.label;
status.briefingDate = p.today;
status.storyCount = p.storyCount;
status.lastPublishISO = nowISO;
status.lastPublishLabel = p.label + ' (auto via n8n)';

const pretty = JSON.stringify(status, null, 2);
return [{ json: {
  statusB64: Buffer.from(pretty, 'utf8').toString('base64'),
  sha: gh.sha,
  today: p.today
} }];
